import { writeOutput } from "./codegen";

const DOCS_URL = "https://faire.github.io/external-api-v2-docs/";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Faire External API V2 docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:faire",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const faireFirewall = {",
    '  name: "faire",',
    '  description: "Faire External API V2",',
    "  placeholders: {",
    `    FAIRE_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://www.faire.com/external-api/v2",',
    "      auth: {",
    "        headers: {",
    '          "X-FAIRE-ACCESS-TOKEN": "${{ secrets.FAIRE_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [",
    "        {",
    '          name: "read",',
    '          description: "Read Faire resources",',
    '          rules: ["GET /{path+}"],',
    "        },",
    "        {",
    '          name: "write",',
    '          description: "Create, update, and delete Faire resources",',
    "          rules: [",
    '            "POST /{path+}",',
    '            "PUT /{path+}",',
    '            "PATCH /{path+}",',
    '            "DELETE /{path+}",',
    "          ],",
    "        },",
    "      ],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Faire firewall config...");
  const ts = generateTypeScript();
  writeOutput("faire", ts, import.meta.dirname);
}
